#!/usr/bin/env python3
import os, base64
b64 = ''
path = "app\\onboarding\\page.tsx"
path = path.replace("\\\\", os.sep).replace("\\", os.sep)
with open(path, "wb") as f:
    f.write(base64.b64decode(b64))
print("Done — git add . && git commit -m \"Fix onboarding skip goes to done\" && vercel --prod")
